20	};
21	
22	const roundUpInMHPCOFavor = (amount: number): number =>
23	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
24	
25	const basePremiumFor = (items: Array<Item>): number => {
26	  const runes = items.filter((item) => item.type === "rune").length;
27	  if (runes === 3) return BLOCK_OF_THREE_RUNES_PRICE;
28	  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
29	};
30	
31	const withFirstInsuranceSurcharge = (amount: number): number =>
32	  amount * (1 + FIRST_INSURANCE_SURCHARGE);
33	
34	const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;
35	
36	const quoteStep = (step: QuoteStep): { premium: number } => {
37	  const basePremium = basePremiumFor(step.items);
38	  const premiumBeforeRounding = withProcessingFee(
39	    withFirstInsuranceSurcharge(basePremium),
40	  );
41	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
42	};
43	
44	export const processScenario = (scenario: unknown): unknown => {
45	  const { steps } = scenario as Scenario;
46	  return { results: steps.map(quoteStep) };
47	};
