const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FLOAT_ROUNDING_TOLERANCE = 1e-9;
const BLOCK_OF_THREE_DISCOUNT = 15;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);

const sumOfBasePrices = (items: Array<Item>): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const runeBlockDiscount = (items: Array<Item>): number => {
  const runes = items.filter((item) => item.type === "rune").length;
  return runes === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
};

const basePremiumFor = (items: Array<Item>): number =>
  sumOfBasePrices(items) - runeBlockDiscount(items);
